head.script:
scwin.referDtaCnt = 0; // 참고자료개수

scwin.popupParam;

/**
 * 로딩시 화면 설정
 */
scwin.initScreen = function() {
	scwin.popupParam=comLib.getPopupParam($p);
	scwin.searchImgFile();
	scwin.searchReferDta();
	$p.$("#imgPop").on("load", function() {
		var width = $(this).width() + 15;
		var height = $(this).height() + 105;
		window.resizeTo(width, height);
	});
};

/**
 * 첨부파일 조회
 * 게시물 첨부파일 중 첫번째 첨부파일만 화면에 뿌려준다.
 */
scwin.searchImgFile = function() {
	var requestData = { };
	requestData.dltFile = { };
	requestData.dltFile.atchflId = scwin.popupParam.atchflId;
	requestData.dltFile.fileSeq = 1;

	var option = {
		action : "sc/file/imgFileView.do",
		reqData : requestData,
		success : "scwin.searchImgFileCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 첨부파일 조회 Callback
 */
scwin.searchImgFileCallback = function(resBody) {
	if (resBody.message.code == "success") {
		imgPop.setSrc(resBody.data.imgData);
	}
};

/**
 * 참고자료 조회
 * 1번 첨부파일은 팝업이미지이고
 * 나머지 파일들이 참고자료
 */
scwin.searchReferDta = function() {
	var requestData = { };
	requestData.dmaFileBasic = { };
	requestData.dmaFileBasic.atchflId = scwin.popupParam.atchflId;

	var option = {
		action : "sc/file/fileList.do",
		reqData : requestData,
		success : "scwin.searchReferDtaCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 참고자료 조회 Callback
 */
scwin.searchReferDtaCallback = function(resBody) {
	if (resBody.message.code == "success") {
		scwin.referDtaCnt = resBody.data.length;
		if (scwin.referDtaCnt > 1) {
			btnReferDta.setStyle("display", "");
		}
	}
};

/**
 * 참고자료 다운로드
 */
scwin.btnReferDta_onclick = function() {
	// 단건 파일은 일반 다운로드
	if (scwin.referDtaCnt == 2) {
		var referDtaOne = {
			"atchflId" : scwin.popupParam.atchflId,
			"fileSeq" : 2
		};
		var xmlValue = JSON.stringify(referDtaOne);
		// $w.download("/sc/file/downloadAtchFileOne.do", xmlValue, "post");
		comLib.downloadAtchfl("/sc/file/downloadAtchFileOne.do", xmlValue, "post");
	// 다건 파일은 일괄 다운로드 로직
	} else {
		var referDtaMulti = [];
		for (i = 2 ; i <= scwin.referDtaCnt ; i++) {
			var referDtaOne = {
				"atchflId" : scwin.popupParam.atchflId,
				"fileSeq" : i
			};
			referDtaMulti.push(referDtaOne);
		}
		var xmlValue = JSON.stringify(referDtaMulti);
		// $w.download( "/sc/file/downloadAtchFile.do", xmlValue, "post");
		comLib.downloadAtchfl("/sc/file/downloadAtchFileOne.do", xmlValue, "post");

	}
};

/**
 * 하루동안 보이지 않음
 */
scwin.btnPoupDayClose_onchange = function() {
	comLib.setCookie($p, "NOTICE_POPUP_" + scwin.popupParam.noticeId, "Y", 1);
	close();
};
